void PrintCopyrightNotice() {
    std::string product = CopyrightCrypto::GetProductName();
    std::string copyright = CopyrightCrypto::GetCopyrightText();
    std::string notice = CopyrightCrypto::GetNonCommercialNotice();

    std::cout << "================================================================================" << std::endl;
    std::cout << "[" << product << "] " << copyright << std::endl;
    std::cout << "[" << product << "] " << notice << std::endl;
    std::cout << "================================================================================" << std::endl;
}

bool ValidateCopyrightAndKey(const std::string& config_key, std::string& out_reason) {
    std::string product = CopyrightCrypto::GetProductName();
    std::string expected_key = CopyrightCrypto::GetApiKey();

    if (config_key.empty()) {
        out_reason = "[" + product + "] ERROR: API key missing in config.json";
        return false;
    }

    if (config_key != expected_key) {
        out_reason = "[" + product + "] ERROR: API key mismatch - plugin will not start";
        return false;
    }

    out_reason = "[" + product + "] Copyright and API key validated";
    return true;
}
